import{_ as o,o as t,c as r,ai as s}from"./chunks/framework.CPhGBfAl.js";const m=JSON.parse('{"title":"赞助","description":"","frontmatter":{},"headers":[],"relativePath":"sponser.md","filePath":"sponser.md"}'),a={name:"sponser.md"};function n(p,e,i,c,d,l){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="赞助" tabindex="-1">赞助 <a class="header-anchor" href="#赞助" aria-label="Permalink to “赞助”">​</a></h1><p><strong>赞助是获得不影响游戏平衡的游戏权限的重要途径</strong>，主要包括三种方式：直接购买点券、购买月卡（减负包）以及参与众筹。</p><ul><li><p>点券是用于购买权限的主要代币，<strong>可兑换游戏币、装饰性或功能性的权限（如彩色聊天字体、更多附魔查询、称号装饰、增加上架物品数量等）</strong>，有效期通常为一个月。</p></li><li><p><strong>月卡（减负包）为按月订阅服务</strong>，购买后可一次性获得200点券，并每日领取800游戏币和一个不死图腾；在有效期内，还能享受圈地价格降低0.1、领地上限+1，以及mcmmo经验获取增加10%的福利。</p></li><li><p>众筹则在服务器需要添加新插件时开放，<strong>由多名玩家共同赞助以筹集所需金额</strong>。参与众筹的玩家将加入众筹组，获得额外的领地及设家上限，并解锁部分娱乐和功能性插件权限（例如CMI的装饰性功能，如<code>/ride</code>、<code>/hat</code>、盔甲架编辑等），<strong>这些权限均以娱乐和便利为主，不会影响玩家间的游戏平衡。</strong></p></li></ul><p>前两种可以在游戏中输入<code>/菜单</code>后，于界面右下角点击赞助菜单进入相关界面。</p>',4)])])}const g=o(a,[["render",n]]);export{m as __pageData,g as default};
